SELECT Н_ТИПЫ_ВЕДОМОСТЕЙ.ИД, Н_ВЕДОМОСТИ.ДАТА FROM Н_ТИПЫ_ВЕДОМОСТЕЙ, Н_ВЕДОМОСТИ WHERE Н_ТИПЫ_ВЕДОМОСТЕЙ.ИД = 2 AND Н_ВЕДОМОСТИ.ИД > 1250981;
SELECT Н_ЛЮДИ.ОТЧЕСТВО, Н_ВЕДОМОСТИ.ЧЛВК_ИД, Н_СЕССИЯ.ЧЛВК_ИД FROM Н_ЛЮДИ, Н_ВЕДОМОСТИ, Н_СЕССИЯ WHERE Н_ЛЮДИ.ИД = 100865 AND Н_ВЕДОМОСТИ.ИД > 1250981 AND Н_СЕССИЯ.УЧГОД > 2008/2009;
